package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testParseReturnsCSVParserInstance() throws Exception {
        Reader mockReader = mock(Reader.class);
        CSVParser mockParser = mock(CSVParser.class);

        // Use reflection to create a subclass proxy by subclassing CSVFormat anonymously
        CSVFormat proxyFormat = new CSVFormat(
                csvFormat.getDelimiter(),
                csvFormat.getQuoteChar(),
                csvFormat.getQuotePolicy(),
                csvFormat.getCommentStart(),
                csvFormat.getEscape(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord()) {
            @Override
            public CSVParser parse(final Reader in) throws IOException {
                return mockParser;
            }
        };

        CSVParser parser = proxyFormat.parse(mockReader);

        assertNotNull(parser);
        assertSame(mockParser, parser);
    }

    @Test
    void testParseThrowsIOException() throws Exception {
        Reader mockReader = mock(Reader.class);

        CSVFormat proxyFormat = new CSVFormat(
                csvFormat.getDelimiter(),
                csvFormat.getQuoteChar(),
                csvFormat.getQuotePolicy(),
                csvFormat.getCommentStart(),
                csvFormat.getEscape(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord()) {
            @Override
            public CSVParser parse(final Reader in) throws IOException {
                throw new IOException("mock IO exception");
            }
        };

        IOException thrown = assertThrows(IOException.class, () -> {
            proxyFormat.parse(mockReader);
        });

        assertEquals("mock IO exception", thrown.getMessage());
    }
}
